def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_capacity
        score = 0
        if ratio > 2:
            score = ratio ** 4 + np.log(ratio)
        elif ratio > 1:
            score = (ratio ** 3) * 1.2
            for k in range(1, 4):
                score += (ratio / k) ** k
        elif ratio == 1:
            score = 0
        else:
            for j in range(1, 7):
                if j % 2 == 0:
                    score += (ratio ** j) / (j * 1.5)
                else:
                    score += (ratio ** j) / j
            if bin_capacity < item * 1.5:
                score *= 2
            elif bin_capacity < item * 3:
                score *= 1.3
            else:
                for m in range(3):
                    score += (bin_capacity / (item + 1)) ** (m + 1) / (m + 2)
        if bin_capacity % 2 == 0:
            score *= 0.9
        else:
            score *= 1.1
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 2.5
        elif priorities[i] < 0:
            priorities[i] = abs(priorities[i]) + max_priority * 0.5
    return priorities
